# {The new algorithm incorporates a dynamic priority score for each customer that adjusts based on their proximity to the truck, future demand predicted by considering other trucks' paths, and the potential to optimize the fleet's coverage efficiency, with the goal of minimizing idle time.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    priority_scores = []
    truck_count = len(all_truck_pos)

    for idx, customer in enumerate(unvisited_customers):
        # Calculate distance from current truck
        truck_distance = distance(cur_truck_pos, customer)

        # Calculate potential demand impact by considering other trucks' paths
        future_demand_impact = sum(1 / (1 + distance(truck_pos, customer)) for truck_pos in all_truck_pos)

        # Calculate proximity to depot
        depot_distance_factor = 1 / (1 + distance(depot_pos, customer))

        # Compute dynamic priority score
        priority_score = 0.6 * truck_distance + 0.2 * future_demand_impact + 0.2 * depot_distance_factor
        priority_scores.append((idx, priority_score))

    # Select node with minimum priority score
    if priority_scores:
        best_node = min(priority_scores, key=lambda x: x[1])[0]
    else:
        best_node = None

    return best_node

