# Common backbone idea: Both algorithms use a notion of distance as a measure to prioritize selecting the next node, also considering factors to optimize the workload and completion time across all trucks.

# Description of the new algorithm: {The algorithm evaluates potential next nodes by employing a distance-gradient approach, incorporating both distance differentials between customers and the average proximity to the depot, aiming to minimize variance in workload distribution.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    gradients = []
    depot_avg_proximity = np.mean([distance(depot_pos, customer) for customer in unvisited_customers])

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer)
        proximity_diff = abs(depot_avg_proximity - distance(depot_pos, customer))

        gradient = dist_to_customer + proximity_diff
        gradients.append((i, gradient))

    gradients.sort(key=lambda x: x[1])
    best_node = gradients[0][0]

    return best_node

